import java.util.*;

public class VersionConflictResolver {

    public record VersionCandidate(String version, int depth) {}

    public String resolveNearest(List<VersionCandidate> candidates) {
        // Maven strategy: return the version with the smallest depth
        // On tie, return the first one in the list
        return "";
    }

    public String resolveHighest(List<VersionCandidate> candidates) {
        // Gradle strategy: return the highest semantic version
        // Versions are in 'MAJOR.MINOR.PATCH' format
        return "";
    }

    private int[] parseVersion(String version) {
        // Parse 'MAJOR.MINOR.PATCH' into an int array [major, minor, patch]
        String[] parts = version.split("\\.");
        return new int[]{ Integer.parseInt(parts[0]), Integer.parseInt(parts[1]), Integer.parseInt(parts[2]) };
    }

    public static void main(String[] args) {
        VersionConflictResolver resolver = new VersionConflictResolver();
        List<VersionCandidate> candidates = List.of(
            new VersionCandidate("2.1.0", 3),
            new VersionCandidate("1.9.5", 1),
            new VersionCandidate("3.0.0", 2)
        );
        System.out.println("Nearest: " + resolver.resolveNearest(candidates));
        System.out.println("Highest: " + resolver.resolveHighest(candidates));
    }
}

