import java.util.*;

public class BomEnforcer {

    private final Map<String, String> bomVersions = new HashMap<>();

    public void importBom(Map<String, String> bom) {
        // Register artifact -> approved version mappings from the BOM
        bomVersions.putAll(bom);
    }

    public List<String> enforceVersions(Map<String, String> projectDeps) {
        // Check each projectDep against BOM versions
        // Return list of violation messages for mismatches
        // Format: 'VIOLATION: artifact uses X but BOM requires Y'
        return new ArrayList<>();
    }

    public Map<String, String> resolveVersions(Map<String, String> projectDeps) {
        // Return a new map: if dep has no version (empty string), use BOM version
        // If dep has a version and it matches BOM, keep it
        // If dep has a version that doesn't match BOM, keep project version (override)
        return new HashMap<>();
    }

    public static void main(String[] args) {
        BomEnforcer enforcer = new BomEnforcer();
        enforcer.importBom(Map.of(
            "spring-core", "6.0.0",
            "spring-web", "6.0.0",
            "jackson", "2.14.0"
        ));

        Map<String, String> projectDeps = Map.of(
            "spring-core", "5.3.0",
            "spring-web", "6.0.0",
            "jackson", ""
        );

        System.out.println(enforcer.enforceVersions(projectDeps));
        Map<String, String> resolved = enforcer.resolveVersions(projectDeps);
        System.out.println("jackson resolved to: " + resolved.get("jackson"));
    }
}
